///SB, DLT, 30/04/2026
/// <summary>
/// COC of standard method to add custom BatchId
/// </summary>
public void insert()
{
    if(ETGCanadaParameters::find().EnableDefaultBatchNumber == NoYes::Yes)
    {
        InventDim inventDim = this.inventDim();

        if(inventDim.InventBatchId == '')
        {
            inventDim.InventBatchId = inventTable::find(this.ItemId).ETGDefaultBatchNumber;
            this.InventDimId = InventDim::findOrCreate(inventDim).InventDimId;
        }
    }

    next insert();
}
